-- Multi-facility Programming Library backfill.
-- IDEMPOTENT. Generated by scripts/generate-144-programming-facility-backfill.mjs
-- Seed 141 inserts into the canonical facility only; this clones all 50 methods
-- plus child rows to every other facility missing those slugs.

WITH canonical AS (
  SELECT id AS facility_id FROM public.facility ORDER BY id LIMIT 1
)
INSERT INTO coaching.programming_method (
  facility_id, name, slug, category, definition, coach_summary, athlete_summary,
  primary_development_goal, secondary_development_goals, programming_type,
  best_session_phase, compatible_session_phases, incompatible_phases,
  energy_system_focus, fatigue_profile, supervision_level,
  what_it_is, why_it_matters, when_to_use, when_not_to_use, common_misuse,
  work_rest_structure, exercise_compatibility, scaling, progression_logic, regression_logic,
  workout_builder_rules, is_published, visibility, archived
)
SELECT
  f.id,
  src.name, src.slug, src.category, src.definition, src.coach_summary, src.athlete_summary,
  src.primary_development_goal, src.secondary_development_goals, src.programming_type,
  src.best_session_phase, src.compatible_session_phases, src.incompatible_phases,
  src.energy_system_focus, src.fatigue_profile, src.supervision_level,
  src.what_it_is, src.why_it_matters, src.when_to_use, src.when_not_to_use, src.common_misuse,
  src.work_rest_structure, src.exercise_compatibility, src.scaling, src.progression_logic, src.regression_logic,
  src.workout_builder_rules, src.is_published, src.visibility, FALSE
FROM coaching.programming_method src
CROSS JOIN public.facility f
CROSS JOIN canonical c
WHERE src.facility_id = c.facility_id
  AND src.archived = FALSE
  AND f.id <> c.facility_id
  AND NOT EXISTS (
    SELECT 1 FROM coaching.programming_method tgt
    WHERE tgt.facility_id = f.id AND tgt.slug = src.slug
  );

WITH canonical AS (
  SELECT id AS facility_id FROM public.facility ORDER BY id LIMIT 1
),
pairs AS (
  SELECT src.id AS src_id, tgt.id AS tgt_id
  FROM coaching.programming_method src
  JOIN coaching.programming_method tgt ON tgt.slug = src.slug AND tgt.facility_id <> src.facility_id
  JOIN canonical c ON src.facility_id = c.facility_id
  WHERE src.archived = FALSE
)
INSERT INTO coaching.programming_method_phase_profile (
  programming_method_id, phase_key, role, fit_weight, phase_rationale, fatigue_rationale, order_rationale, risk_note
)
SELECT
  p.tgt_id, pp.phase_key, pp.role, pp.fit_weight, pp.phase_rationale, pp.fatigue_rationale, pp.order_rationale, pp.risk_note
FROM pairs p
JOIN coaching.programming_method_phase_profile pp ON pp.programming_method_id = p.src_id
ON CONFLICT (programming_method_id, phase_key) DO UPDATE SET
  role = EXCLUDED.role,
  fit_weight = EXCLUDED.fit_weight,
  phase_rationale = EXCLUDED.phase_rationale,
  fatigue_rationale = EXCLUDED.fatigue_rationale,
  order_rationale = EXCLUDED.order_rationale,
  risk_note = EXCLUDED.risk_note;

WITH canonical AS (
  SELECT id AS facility_id FROM public.facility ORDER BY id LIMIT 1
),
pairs AS (
