INSERT INTO coaching.programming_method_prescription_profile (
  programming_method_id, profile_name, age_min, age_max, skill_level,
  default_total_minutes, default_rounds, default_work_seconds, default_rest_seconds,
  default_rest_between_rounds_seconds, default_station_seconds, default_cap_minutes,
  default_rpe_min, default_rpe_max, default_heart_rate_zone, notes
)
SELECT
  p.tgt_id, rx.profile_name, rx.age_min, rx.age_max, rx.skill_level,
  rx.default_total_minutes, rx.default_rounds, rx.default_work_seconds, rx.default_rest_seconds,
  rx.default_rest_between_rounds_seconds, rx.default_station_seconds, rx.default_cap_minutes,
  rx.default_rpe_min, rx.default_rpe_max, rx.default_heart_rate_zone, rx.notes
FROM pairs p
JOIN coaching.programming_method_prescription_profile rx ON rx.programming_method_id = p.src_id
ON CONFLICT (programming_method_id, profile_name) DO UPDATE SET
  default_total_minutes = EXCLUDED.default_total_minutes,
  default_rounds = EXCLUDED.default_rounds,
  default_work_seconds = EXCLUDED.default_work_seconds,
  default_rest_seconds = EXCLUDED.default_rest_seconds,
  default_rest_between_rounds_seconds = EXCLUDED.default_rest_between_rounds_seconds,
  default_station_seconds = EXCLUDED.default_station_seconds,
  default_cap_minutes = EXCLUDED.default_cap_minutes,
  default_rpe_min = EXCLUDED.default_rpe_min,
  default_rpe_max = EXCLUDED.default_rpe_max,
  default_heart_rate_zone = EXCLUDED.default_heart_rate_zone,
  notes = EXCLUDED.notes;

WITH canonical AS (
  SELECT id AS facility_id FROM public.facility ORDER BY id LIMIT 1
),
pairs AS (
  SELECT src.id AS src_id, tgt.id AS tgt_id
  FROM coaching.programming_method src
  JOIN coaching.programming_method tgt ON tgt.slug = src.slug AND tgt.facility_id <> src.facility_id
  JOIN canonical c ON src.facility_id = c.facility_id
  WHERE src.archived = FALSE
)
INSERT INTO coaching.programming_method_exercise_compatibility (
  programming_method_id, compatibility_type, exercise_type, facet_type, facet_key, weight, rationale, constraints
)
SELECT
  p.tgt_id, ec.compatibility_type, ec.exercise_type, ec.facet_type, ec.facet_key, ec.weight, ec.rationale, ec.constraints
FROM pairs p
JOIN coaching.programming_method_exercise_compatibility ec ON ec.programming_method_id = p.src_id
WHERE NOT EXISTS (
  SELECT 1 FROM coaching.programming_method_exercise_compatibility existing
  WHERE existing.programming_method_id = p.tgt_id
    AND existing.compatibility_type = ec.compatibility_type
    AND existing.exercise_type = ec.exercise_type
    AND COALESCE(existing.facet_type, '') = COALESCE(ec.facet_type, '')
    AND COALESCE(existing.facet_key, '') = COALESCE(ec.facet_key, '')
);

